from pathlib import Path
import ast, json, os, re, shutil, subprocess, sys, tempfile
p=Path(r'Z:\FOXAI\core\foxai_web.py')
source=p.read_text(encoding='utf-8')
tree=ast.parse(source)
html_value=None
for item in tree.body:
    if isinstance(item,(ast.Assign,ast.AnnAssign)):
        targets=item.targets if isinstance(item,ast.Assign) else [item.target]
        if any(isinstance(t,ast.Name) and t.id=='HTML' for t in targets):
            html_value=ast.literal_eval(item.value)
            break
assert isinstance(html_value,str), 'HTML constant not found'
blocks=re.findall(r'<script(?:\s[^>]*)?>(.*?)</script>',html_value,flags=re.I|re.S)
javascript='\n;\n'.join(blocks)
start=javascript.index('/* KAYOCK_WRITER_CALM_CLEANUP_V1_JS_START */')
end=javascript.index('/* KAYOCK_WRITER_CALM_CLEANUP_V1_JS_END */',start)+len('/* KAYOCK_WRITER_CALM_CLEANUP_V1_JS_END */')
cleanup_block=javascript[start:end]
node=shutil.which('node') or shutil.which('node.exe')
if not node:
    candidate=Path(os.environ.get('ProgramFiles',r'C:\Program Files'))/'nodejs'/'node.exe'
    if candidate.is_file():
        node=str(candidate)
assert node, 'Node.js was not found for Writer task-memory simulation'
test=r'''
const assert=require('assert');
const vm=require('vm');
const memory={};
const fields={};
const calls=[];
const context={
 console,
 localStorage:{
  getItem:k=>Object.prototype.hasOwnProperty.call(memory,k)?memory[k]:null,
  setItem:(k,v)=>{memory[k]=String(v)}
 },
 navRecents:()=>['kayockwriter','storyforge'],
 q:(id)=>({classList:{contains:()=>false},scrollIntoView:()=>{},focus:()=>{}}),
 go:(page)=>calls.push(['go',page]),
 toast:(msg)=>calls.push(['toast',msg]),
 setPoetryStudioField:(id,v)=>{fields[id]=v;calls.push(['field',id,v])},
 updateCreatorWritingType:()=>calls.push(['update']),
 openPoemPolisherFromWriterHome:()=>calls.push(['poem_polisher']),
 openShortStoryPolisherFromWriterHome:()=>calls.push(['short_story_polisher']),
 setTimeout:(fn)=>{fn();return 1}
};
vm.createContext(context);
vm.runInContext(
 process.env.WRITER_CLEANUP_BLOCK+
 '\n;globalThis.__api={readWriterTask,rememberWriterTask,writerRecentFallback,writerRecentV2,openWriterCreatorFromHome,continueWriterRecentV2,WRITER_TASK_MEMORY_KEY,WRITER_TASK_V1};',
 context
);
const a=context.__api;
for(const id of [
 'poem_creator','short_story_creator','poem_polisher','short_story_polisher',
 'poetry_studio','weaver','poemarchive','storyforge','projectdashboard',
 'draftreader','chapterproseworkspace','savedchapters','worldbuilder','mywriting','novelforge'
]) assert.ok(a.WRITER_TASK_V1[id],id);
assert.strictEqual(a.readWriterTask(),'');
assert.strictEqual(a.writerRecentFallback(),'storyforge');
assert.strictEqual(a.writerRecentV2().id,'storyforge');
a.rememberWriterTask('short_story_creator');
assert.strictEqual(memory[a.WRITER_TASK_MEMORY_KEY],'short_story_creator');
assert.strictEqual(a.writerRecentV2().label,'Short Story Creator');
calls.length=0;
a.openWriterCreatorFromHome('short_story');
assert.strictEqual(fields.poemWritingType,'short_story');
assert.deepStrictEqual(calls.slice(0,3),[
 ['field','poemWritingType','short_story'],['update'],['go','poetrystudio']
]);
a.rememberWriterTask('poem_polisher');
calls.length=0;
a.continueWriterRecentV2();
assert.deepStrictEqual(calls,[['poem_polisher']]);
a.rememberWriterTask('short_story_polisher');
calls.length=0;
a.continueWriterRecentV2();
assert.deepStrictEqual(calls,[['short_story_polisher']]);
a.rememberWriterTask('weaver');
calls.length=0;
a.continueWriterRecentV2();
assert.deepStrictEqual(calls,[['go','weaver']]);
a.rememberWriterTask('worldbuilder');
calls.length=0;
a.continueWriterRecentV2();
assert.deepStrictEqual(calls,[['go','worldbuilder']]);
console.log('KAYOCK_WRITER_CALM_CLEANUP_1_0_TASK_MEMORY_SIMULATION_OK');
'''
temp_path=None
try:
    with tempfile.NamedTemporaryFile('w',suffix='.js',encoding='utf-8',delete=False) as handle:
        handle.write(test)
        temp_path=handle.name
    env=dict(os.environ)
    env['WRITER_CLEANUP_BLOCK']=cleanup_block
    result=subprocess.run([str(node),temp_path],capture_output=True,text=True,shell=False,env=env)
    if result.stdout:
        print(result.stdout)
    if result.stderr:
        print(result.stderr,file=sys.stderr)
    assert result.returncode==0, f'Writer task-memory simulation failed with return code {result.returncode}'
finally:
    if temp_path:
        try:
            Path(temp_path).unlink()
        except FileNotFoundError:
            pass
